fn worker(m: &'a mutex<St>, cv: &'a condvar) {
  let g = m.lock();            // lock<'m>(&'m mutex<St>) -> guard<'m>  (confined; shared-strength loan)
  loop {
    let p = predicate(&g);     // predicate(&guard<'m>) -> P {Done, Wait}
    match p {
      Done => { break; }
      Wait => {
        let g2 = cv.wait(m, own g);  // wait<'c,'m>(&'c condvar, &'m mutex<St>, own guard<'m>) -> guard<'m>
        g = g2;                       // rebind: move confined value into consumed binding g
      }
    }
  }
}                                // scope end: g auto-consumed -> unlock

